// // This module is designed to decrement a 2-bit counter from 11 to 00 on each positive edge of the clock signal.
module counter_2bit (
    input wire clk,
    input wire reset,
    output reg [1:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 2'b00;
        end else begin
            count <= count + 1;
        end
    end
endmodule
